#include <stdio.h>
#include <string.h>

int solve(char *s1, char *s2) {
    int m = strlen(s1);
    int n = strlen(s2);

    int dp[m];
    for(int i = 0; i < m; i++) dp[i] = 0;

    int longest = 0;

    for(int j = 0; j < n; j++) {
        int curr_len = 0;
        for(int i = 0; i < m; i++) {
            if(curr_len < dp[i]) {
                curr_len = dp[i];
            }
            else if(s2[j] == s1[i]) {
                dp[i] = curr_len + 1;
                if(dp[i] > longest)
                    longest = dp[i];
            }
        }
    }
    return longest;
}

