import java.util.*;

public class Main {

    static int solve(String s1, String s2) {
        int m = s1.length();
        int[] dp = new int[m];
        int longest = 0;

        for(int j = 0; j < s2.length(); j++) {
            int curr_len = 0;
            char c = s2.charAt(j);

            for(int i = 0; i < m; i++) {
                if(curr_len < dp[i]) {
                    curr_len = dp[i];
                } 
                else if(c == s1.charAt(i)) {
                    dp[i] = curr_len + 1;
                    longest = Math.max(longest, dp[i]);
                }
            }
        }
        return longest;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();

        while(t-- > 0) {
            String s1 = sc.next();
            String s2 = sc.next();
            System.out.println(solve(s1, s2));
        }
        sc.close();
    }
}
